47.         {
48.             var assembly = Assembly.GetExecutingAssembly();
49.             using (Stream stream = assembly.GetManifestResourceStream(profile.GetManifestName()))
50.             {
51.                 var memory = BinaryData.FromStream(stream).ToMemory();
52.                 using var doc = JsonDocument.Parse(memory);
53.                 var armProfile = doc.RootElement.GetProperty("resource-manager");
54.                 foreach (var keyValuePair in armProfile.EnumerateObject())
55.                 {
56.                     var namespaceName = keyValuePair.Name;
57.                     var element = keyValuePair.Value;
58.                     foreach (var apiVersionProperty in element.EnumerateObject())
59.                     {
60.                         var apiVersion = apiVersionProperty.Name;
61.                         foreach (var resourceTypeItem in apiVersionProperty.Value.EnumerateArray())
62.                         {
63.                             string resourceTypeName = default;
64.                             foreach (var property in resourceTypeItem.EnumerateObject())
65.                             {
66.                                 if (property.NameEquals("resourceType"))
67.                                 {
68.                                     resourceTypeName = property.Value.GetString();
69.                                     break;
70.                                 }
71.                             }
72.                             var resourceType = $"{namespaceName}/{resourceTypeName}";
73.                             ResourceApiVersionOverrides[resourceType] = apiVersion;
